# shapes.spy - Shape hierarchy module
# Provides geometric shapes with inheritance and interface implementation

interface IDrawable:
    def draw(self) -> str: ...

@abstract
class Shape:
    name: str

    def __init__(self, name: str):
        self.name = name

    @abstract
    def area(self) -> float: ...

    @virtual
    def describe(self) -> str:
        return f"{self.name} with area {self.area()}"

class Rectangle(Shape, IDrawable):
    width: float
    height: float

    def __init__(self, name: str, width: float, height: float):
        super().__init__(name)
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    def draw(self) -> str:
        return f"Drawing rectangle '{self.name}' ({self.width} x {self.height})"

class Circle(Shape, IDrawable):
    radius: float

    def __init__(self, name: str, radius: float):
        super().__init__(name)
        self.radius = radius

    @override
    def area(self) -> float:
        pi: float = 3.14159
        return pi * self.radius * self.radius

    def draw(self) -> str:
        return f"Drawing circle '{self.name}' (r={self.radius})"

