# utils.spy - Utility functions module
# Provides helper functions for shape operations

from shapes import Shape, Rectangle

def calculate_total_area(shapes: list[Shape]) -> float:
    """Calculate total area of all shapes in the list."""
    total: float = 0.0
    for shape in shapes:
        total += shape.area()
    return total

def create_square(name: str, side: float) -> Rectangle:
    """Factory function to create a square (special rectangle)."""
    return Rectangle(name, side, side)

def format_shape_info(shape: Shape) -> str:
    """Format shape information as a string."""
    return f"[{shape.describe()}]"
